solution_code:
#include <stdio.h>
#include <pthread.h>

int counter = 0;

void *increment(void *arg) {
    (void)arg;
    for (int i = 0; i < 3; i++) {
        int tmp = counter;
        counter = tmp + 1;
    }
    return NULL;
}

int main(void) {
    pthread_t t[3];
    for (int i = 0; i < 3; i++)
        pthread_create(&t[i], NULL, increment, NULL);
    for (int i = 0; i < 3; i++)
        pthread_join(t[i], NULL);
    printf("Counter: %d\n", counter);
    return 0;
}

